import{_ as n,o as r,c as i,ag as t}from"./chunks/framework.CvgP6Fyv.js";const c=JSON.parse('{"title":"Wiederkehrende Rechnungen","description":"","frontmatter":{},"headers":[],"relativePath":"de/features/recurring-invoices.md","filePath":"de/features/recurring-invoices.md"}'),a={name:"de/features/recurring-invoices.md"};function l(h,e,s,o,d,u){return r(),i("div",null,[...e[0]||(e[0]=[t('<h1 id="wiederkehrende-rechnungen" tabindex="-1">Wiederkehrende Rechnungen <a class="header-anchor" href="#wiederkehrende-rechnungen" aria-label="Permalink to &quot;Wiederkehrende Rechnungen&quot;">​</a></h1><p>Automatisieren Sie Ihre regelmäßige Abrechnung, indem Sie Rechnungen einrichten, die nach einem Zeitplan generiert werden.</p><h2 id="ubersicht" tabindex="-1">Übersicht <a class="header-anchor" href="#ubersicht" aria-label="Permalink to &quot;Übersicht&quot;">​</a></h2><p>Wiederkehrende Rechnungen sind Vorlagen, die automatisch neue Rechnungen in festgelegten Intervallen erstellen. Ideal für:</p><ul><li>Monatliche Honorare</li><li>Abonnementabrechnungen</li><li>Mieteinnahmen</li><li>Wartungsverträge</li><li>Regelmäßige Beratungshonorare</li></ul><h2 id="wiederkehrende-rechnung-erstellen" tabindex="-1">Wiederkehrende Rechnung erstellen <a class="header-anchor" href="#wiederkehrende-rechnung-erstellen" aria-label="Permalink to &quot;Wiederkehrende Rechnung erstellen&quot;">​</a></h2><ol><li>Gehen Sie zu <strong>Wiederkehrende Rechnungen &gt; Neu</strong></li><li>Füllen Sie die Vorlage aus: <ul><li><strong>Kunde</strong> — Wem abgerechnet wird</li><li><strong>Positionen</strong> — Was abgerechnet wird (Beschreibungen, Beträge, USt.)</li><li><strong>Häufigkeit</strong> — Wie oft (wöchentlich, monatlich, vierteljährlich, jährlich)</li><li><strong>Startdatum</strong> — Wann die Generierung beginnen soll</li></ul></li><li>Klicken Sie auf <strong>Speichern</strong></li></ol><p>Die wiederkehrende Rechnung wird im Status <strong>Aktiv</strong> erstellt und generiert ihre erste Rechnung am nächsten geplanten Datum.</p><h2 id="haufigkeitsoptionen" tabindex="-1">Häufigkeitsoptionen <a class="header-anchor" href="#haufigkeitsoptionen" aria-label="Permalink to &quot;Häufigkeitsoptionen&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Häufigkeit</th><th>Beschreibung</th></tr></thead><tbody><tr><td><strong>Wöchentlich</strong></td><td>Alle 7 Tage</td></tr><tr><td><strong>Monatlich</strong></td><td>Am gleichen Tag jeden Monat</td></tr><tr><td><strong>Vierteljährlich</strong></td><td>Alle 3 Monate</td></tr><tr><td><strong>Jährlich</strong></td><td>Einmal pro Jahr</td></tr></tbody></table><h2 id="wiederkehrende-rechnungen-verwalten" tabindex="-1">Wiederkehrende Rechnungen verwalten <a class="header-anchor" href="#wiederkehrende-rechnungen-verwalten" aria-label="Permalink to &quot;Wiederkehrende Rechnungen verwalten&quot;">​</a></h2><h3 id="pausieren" tabindex="-1">Pausieren <a class="header-anchor" href="#pausieren" aria-label="Permalink to &quot;Pausieren&quot;">​</a></h3><p>Rechnungsgenerierung vorübergehend stoppen:</p><ol><li>Öffnen Sie die wiederkehrende Rechnung</li><li>Klicken Sie auf <strong>Pausieren</strong></li><li>Der Status ändert sich zu <strong>Pausiert</strong> — es werden keine Rechnungen generiert</li></ol><h3 id="fortsetzen" tabindex="-1">Fortsetzen <a class="header-anchor" href="#fortsetzen" aria-label="Permalink to &quot;Fortsetzen&quot;">​</a></h3><p>Eine pausierte wiederkehrende Rechnung fortsetzen:</p><ol><li>Öffnen Sie die pausierte wiederkehrende Rechnung</li><li>Klicken Sie auf <strong>Fortsetzen</strong></li><li>Die Generierung wird ab dem nächsten geplanten Datum fortgesetzt</li></ol><h3 id="bearbeiten" tabindex="-1">Bearbeiten <a class="header-anchor" href="#bearbeiten" aria-label="Permalink to &quot;Bearbeiten&quot;">​</a></h3><p>Das Bearbeiten einer wiederkehrenden Rechnung betrifft nur <strong>zukünftige</strong> Rechnungen. Bereits generierte Rechnungen werden nicht geändert.</p><h3 id="loschen" tabindex="-1">Löschen <a class="header-anchor" href="#loschen" aria-label="Permalink to &quot;Löschen&quot;">​</a></h3><p>Entfernen Sie die wiederkehrende Vorlage vollständig. Bereits generierte Rechnungen bleiben in Ihren Unterlagen.</p><h2 id="generierte-rechnungen" tabindex="-1">Generierte Rechnungen <a class="header-anchor" href="#generierte-rechnungen" aria-label="Permalink to &quot;Generierte Rechnungen&quot;">​</a></h2><p>Jedes Mal, wenn eine wiederkehrende Rechnung ausgelöst wird, wird eine neue Rechnung erstellt:</p><ul><li>Sie verwendet die Positionen und den Kunden der Vorlage</li><li>Sie folgt Ihrer aktuellen Rechnungsnummerierung</li><li>Sie beginnt als <strong>Entwurf</strong> (überprüfen und versenden) oder wird automatisch versendet, falls konfiguriert</li><li>Jede generierte Rechnung ist unabhängig — Sie können sie bearbeiten, ohne die Vorlage zu beeinflussen</li></ul><h2 id="verlauf-anzeigen" tabindex="-1">Verlauf anzeigen <a class="header-anchor" href="#verlauf-anzeigen" aria-label="Permalink to &quot;Verlauf anzeigen&quot;">​</a></h2><p>Die Detailseite der wiederkehrenden Rechnung zeigt alle zuvor generierten Rechnungen, sodass Sie den gesamten Abrechnungsverlauf verfolgen können.</p><h2 id="massenaktionen" tabindex="-1">Massenaktionen <a class="header-anchor" href="#massenaktionen" aria-label="Permalink to &quot;Massenaktionen&quot;">​</a></h2><ul><li><strong>Pausieren / Fortsetzen</strong> — Mehrere wiederkehrende Rechnungen umschalten</li><li><strong>Löschen</strong> — Mehrere Vorlagen entfernen</li></ul><h2 id="tipps" tabindex="-1">Tipps <a class="header-anchor" href="#tipps" aria-label="Permalink to &quot;Tipps&quot;">​</a></h2><ul><li>Kombinieren Sie mit <a href="/de/features/contracts">Verträgen</a> für vertragsbasierte Abrechnung</li><li>Überprüfen Sie generierte Rechnungen vor dem ersten automatischen Versand, um sicherzustellen, dass alles korrekt aussieht</li><li>Verwenden Sie die Vorschau des nächsten Vorkommens, um zu sehen, wann die nächste Rechnung erstellt wird</li><li>Prüfen Sie die Anzahl der aktiven Vorlagen und Kennzahlen oben auf der Seite</li></ul>',30)])])}const b=n(a,[["render",l]]);export{c as __pageData,b as default};
